import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import MovieCard from '../components/MovieCard';
import { useAuth } from '../context/AuthContext';

const API_URL = 'http://localhost/cineverse-pro/backend/api/';

const Home = () => {
    const { isAuthenticated } = useAuth();
    const [movies, setMovies] = useState([]);
    const [recommendations, setRecommendations] = useState([]);
    const [loading, setLoading] = useState(true);
    const [heroMovie, setHeroMovie] = useState(null);

    useEffect(() => {
        fetchMovies();
        if (isAuthenticated) fetchRecommendations();
    }, [isAuthenticated]);

    const fetchMovies = async () => {
        try {
            const response = await axios.get(API_URL + 'fetch_movies.php?limit=50');
            if (response.data.success) {
                setMovies(response.data.movies);
                if (response.data.movies.length > 0) {
                    setHeroMovie(response.data.movies[Math.floor(Math.random() * 10)]);
                }
            }
        } catch (err) { console.error('Failed to fetch movies:', err); }
        finally { setLoading(false); }
    };

    const fetchRecommendations = async () => {
        try {
            const response = await axios.get(API_URL + 'get_recommendations.php');
            if (response.data.success) setRecommendations(response.data.recommendations);
        } catch (err) { console.error('Failed to fetch recommendations:', err); }
    };

    const getMoviesByCategory = (category) => {
        const sorted = [...movies].sort((a, b) => {
            if (category === 'trending') return b.views - a.views;
            if (category === 'top_rated') return b.rating - a.rating;
            if (category === 'newest') return new Date(b.created_at) - new Date(a.created_at);
            return 0;
        });
        return sorted.slice(0, 10);
    };

    if (loading) return (<div className="page-loader"><div className="loading-spinner"></div></div>);

    return (
        <div className="home-page" style={{ paddingTop: '80px' }}>
            {heroMovie && (
                <div className="hero-banner">
                    <img src={heroMovie.poster || 'https://via.placeholder.com/1920x1080'} alt={heroMovie.title} />
                    <div className="gradient-overlay"></div>
                    <div className="content">
                        <span className="badge-custom mb-3">{heroMovie.genre}</span>
                        <h1>{heroMovie.title}</h1>
                        <p className="text-truncate" style={{ maxHeight: '100px' }}>{heroMovie.description}</p>
                        <div className="d-flex gap-3 mb-3">
                            <span className="text-warning"><i className="fas fa-star me-1"></i>{heroMovie.rating}/10</span>
                            <span className="text-secondary"><i className="fas fa-calendar me-1"></i>{heroMovie.year}</span>
                            <span className="text-secondary"><i className="fas fa-eye me-1"></i>{(heroMovie.views / 1000000).toFixed(1)}M views</span>
                        </div>
                        <div className="d-flex gap-3">
                            <Link to={'/movie/' + heroMovie.id} className="btn btn-primary btn-lg"><i className="fas fa-play me-2"></i>More Info</Link>
                            <a href={heroMovie.trailer} target="_blank" rel="noopener noreferrer" className="btn btn-secondary btn-lg"><i className="fas fa-play-circle me-2"></i>Watch Trailer</a>
                        </div>
                    </div>
                </div>
            )}

            <div className="container mt-5">
                {isAuthenticated && recommendations.length > 0 && (
                    <section className="mb-5">
                        <h2 className="mb-4" style={{ color: '#e50914' }}><i className="fas fa-magic me-2"></i>Recommended For You</h2>
                        <div className="movie-row">{recommendations.map(movie => <MovieCard key={movie.id} movie={movie} />)}</div>
                    </section>
                )}
                <section className="mb-5">
                    <h2 className="mb-4"><i className="fas fa-fire me-2" style={{ color: '#e50914' }}></i>Trending Now</h2>
                    <div className="movie-row">{getMoviesByCategory('trending').map(movie => <MovieCard key={movie.id} movie={movie} />)}</div>
                </section>
                <section className="mb-5">
                    <h2 className="mb-4"><i className="fas fa-trophy me-2" style={{ color: '#ffd700' }}></i>Top Rated</h2>
                    <div className="movie-row">{getMoviesByCategory('top_rated').map(movie => <MovieCard key={movie.id} movie={movie} />)}</div>
                </section>
                <section className="mb-5">
                    <h2 className="mb-4"><i className="fas fa-clock me-2" style={{ color: '#00d4ff' }}></i>Recently Added</h2>
                    <div className="movie-row">{getMoviesByCategory('newest').map(movie => <MovieCard key={movie.id} movie={movie} />)}</div>
                </section>
                <section className="mb-5">
                    <h2 className="mb-4"><i className="fas fa-star me-2" style={{ color: '#ff6b6b' }}></i>Action Movies</h2>
                    <div className="movie-row">{movies.filter(m => m.genre === 'Action').slice(0, 10).map(movie => <MovieCard key={movie.id} movie={movie} />)}</div>
                </section>
                <section className="mb-5">
                    <h2 className="mb-4"><i className="fas fa-rocket me-2" style={{ color: '#4ecdc4' }}></i>Sci-Fi Adventures</h2>
                    <div className="movie-row">{movies.filter(m => m.genre === 'Sci-Fi').slice(0, 10).map(movie => <MovieCard key={movie.id} movie={movie} />)}</div>
                </section>
                <section className="mb-5">
                    <h2 className="mb-4"><i className="fas fa-heart me-2" style={{ color: '#ff69b4' }}></i>Drama Masterpieces</h2>
                    <div className="movie-row">{movies.filter(m => m.genre === 'Drama').slice(0, 10).map(movie => <MovieCard key={movie.id} movie={movie} />)}</div>
                </section>
            </div>
        </div>
    );
};

export default Home;
